  font-size: 13px;
  z-index: 100;
  pointer-events: none;
  white-space: nowrap;
}

#tooltip {
  position: fixed;
  background: rgba(0, 0, 0, 0.85);
  color: #fff;
  padding: 6px 10px;
  border: 1px solid #555;
  border-radius: 6px;
  font-family: monospace;
  font-size: 12px;
  z-index: 200;
  pointer-events: none;
  display: none;
  white-space: nowrap;
  line-height: 1.5;
}
```

