1	import { MapGrid, GRID_SIZE } from '../map/MapGrid';
2	import { UnitManager } from './UnitManager';
3	import { executeCombat } from './CombatSystem';
4	import type { CombatResult } from './CombatSystem';
5	import type { Unit } from './Unit';
6	
7	export interface EnemyAction {
8	  unit: Unit;
9	  action: 'move' | 'attack' | 'idle';
10	  target?: Unit;
11	  from?: { row: number; col: number };
12	  to?: { row: number; col: number };
13	  combatResult?: CombatResult;
14	}
15	
16	export type CombatFn = (attacker: Unit, defender: Unit, unitManager: UnitManager) => CombatResult;
17	
18	const DIRECTION_OFFSETS: [number, number][] = [
19	  [-1, 0], [1, 0], [0, -1], [0, 1],
20	];
21	
22	export class EnemyAI {
23	  private grid: MapGrid;
24	  private unitManager: UnitManager;
25	  private combatFn: CombatFn;
26	
27	  constructor(
28	    grid: MapGrid,
29	    unitManager: UnitManager,
30	    combatFn?: CombatFn,
31	  ) {
32	    this.grid = grid;
33	    this.unitManager = unitManager;
34	    this.combatFn = combatFn ?? executeCombat;
35	  }
36	
37	  executeTurn(): EnemyAction[] {
38	    const actions: EnemyAction[] = [];
39	    const enemyUnits = this.unitManager.getUnitsByTeam(1);
40	
41	    for (const enemyUnit of enemyUnits) {
42	      if (!enemyUnit.isAlive()) {
43	        continue;
44	      }
45	
46	      const playerUnits = this.unitManager.getUnitsByTeam(0);
47	      if (playerUnits.length === 0) {
48	        break;
49	      }
50	
51	      const nearest = this.findNearest(enemyUnit, playerUnits);
52	      if (!nearest) {
53	        actions.push({ unit: enemyUnit, action: 'idle' });
54	        continue;
55	      }
56	
57	      const adjacent = this.getAdjacentEnemies(enemyUnit);
58	      if (adjacent.length > 0) {
59	        const target = adjacent.sort((a, b) => a.hp - b.hp)[0];
60	        const combatResult = this.combatFn(enemyUnit, target, this.unitManager);
61	        actions.push({
62	          unit: enemyUnit,
63	          action: 'attack',
64	          target,
65	          combatResult,
66	        });
67	      } else {
68	        const moveTarget = this.findBestAdjacentMove(enemyUnit, nearest);
69	        if (moveTarget) {
70	          const from = { row: enemyUnit.row, col: enemyUnit.col };
71	          this.unitManager.moveUnit(enemyUnit, moveTarget.row, moveTarget.col);
72	          actions.push({
73	            unit: enemyUnit,
74	            action: 'move',
75	            from,
76	            to: moveTarget,
77	          });
78	
79	          const postAdjacent = this.getAdjacentEnemies(enemyUnit);
80	          if (postAdjacent.length > 0) {
81	            const target = postAdjacent.sort((a, b) => a.hp - b.hp)[0];
82	            const combatResult = this.combatFn(enemyUnit, target, this.unitManager);
83	            actions.push({
84	              unit: enemyUnit,
85	              action: 'attack',
86	              target,
87	              combatResult,
88	            });
89	          }
90	        } else {
91	          actions.push({ unit: enemyUnit, action: 'idle' });
92	        }
93	      }
94	    }
95	
96	    return actions;
97	  }
98	
99	  findNearest(unit: Unit, targets: Unit[]): Unit | null {
100	    if (targets.length === 0) return null;
101	    return targets.reduce((best, curr) => {
102	      const bestDist = Math.abs(best.row - unit.row) + Math.abs(best.col - unit.col);
103	      const currDist = Math.abs(curr.row - unit.row) + Math.abs(curr.col - unit.col);
104	      return currDist < bestDist ? curr : best;
105	    });
106	  }
107	
108	  getAdjacentEnemies(unit: Unit): Unit[] {
109	    const enemies: Unit[] = [];
110	    for (const [dr, dc] of DIRECTION_OFFSETS) {
111	      const nr = unit.row + dr;
112	      const nc = unit.col + dc;
113	      const target = this.unitManager.getUnitAt(nr, nc);
114	      if (target && target.team !== unit.team && target.isAlive()) {
115	        enemies.push(target);
116	      }
117	    }
118	    return enemies;
119	  }
120	
121	  findBestAdjacentMove(unit: Unit, target: Unit): { row: number; col: number } | null {
122	    let best: { row: number; col: number } | null = null;
123	    let bestDist = Infinity;
124	
125	    for (const [dr, dc] of DIRECTION_OFFSETS) {
126	      const nr = unit.row + dr;
127	      const nc = unit.col + dc;
128	
129	      if (nr < 0 || nr >= GRID_SIZE || nc < 0 || nc >= GRID_SIZE) continue;
130	      if (!this.grid.isPassable(nr, nc)) continue;
131	      if (this.unitManager.isOccupied(nr, nc)) continue;
132	
133	      const dist = Math.abs(nr - target.row) + Math.abs(nc - target.col);
134	      if (dist < bestDist) {
135	        bestDist = dist;
136	        best = { row: nr, col: nc };
137	      }
138	    }
139	
140	    return best;
141	  }
142	}
143

