  const isFlashing = this.animManager.isFlashing(info.unit);
  const color = isFlashing ? '#ffffff' : getUnitColor(info.unit.team);
  drawUnitIcon(this.ctx, info.unit, info.drawX, unitY, TILE_W, TILE_H, HEIGHT_UNIT, SCALE, color);
  const hpBarY = unitY - 18 * SCALE;
  drawHpBar(this.ctx, info.unit, info.drawX, hpBarY, SCALE);
}
```

